/**
 * Processes member/attendee location data into aggregated city-level output.
 *
 * JSON merge mode — PRIMARY. Reads all .json files from scripts/input/member-locations/,
 *             merges them by summing city counts, and writes src/data/member-locations.json.
 *             Files are generated by the /internal/member-map upload tool (no PII).
 *
 * API mode  — set COGNITO_API_KEY env var. Fetches event attendance entries
 *             from all event registration forms, deduplicates by email, and
 *             writes src/data/member-locations.json.
 *
 * CSV mode  — fallback when no JSON files and no COGNITO_API_KEY.
 *             Usage: node scripts/process-member-locations.mjs [input.csv]
 *             Default input: scripts/input/members.csv
 */

import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';
import zipcodes from 'zipcodes';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const ROOT = path.join(__dirname, '..');
const outputFile = path.join(ROOT, 'src', 'data', 'member-locations.json');
const jsonInputDir = path.join(__dirname, 'input', 'member-locations');

const COGNITO_API = 'https://www.cognitoforms.com/api';

// Forms whose names contain any of these strings (case-insensitive) are excluded.
// This lets us filter down to real event registration forms automatically.
const FORM_NAME_EXCLUDES = [
  'draft',
  'demo',
  'proposal',
  'proposals',
  'rates',
  'class registration',
  'staff polling',
  'testing',
];

// Forms whose names must contain one of these to be included (after exclusions).
const FORM_NAME_REQUIRES = ['registration', 'register'];

// ---------------------------------------------------------------------------
// Cognito Forms API helpers
// ---------------------------------------------------------------------------

async function cognitoGet(token, path) {
  const res = await fetch(`${COGNITO_API}${path}`, {
    headers: { Authorization: `Bearer ${token}` },
  });
  if (res.status === 404) return null;
  if (res.status === 429) {
    const retryAfter = res.headers.get('Retry-After');
    const wait = retryAfter ? new Date(retryAfter) - Date.now() : 5000;
    await new Promise((r) => setTimeout(r, Math.max(wait, 1000)));
    return cognitoGet(token, path); // retry once
  }
  if (!res.ok) {
    const body = await res.json().catch(() => ({}));
    throw new Error(`Cognito API ${res.status}: ${body.Message ?? res.statusText} (${path})`);
  }
  return res.json();
}

// Fetch all entries for a form by incrementing entry numbers until 404.
// Uses parallel batches of BATCH_SIZE for speed.
async function fetchAllEntries(token, formId) {
  const BATCH_SIZE = 10;
  const entries = [];
  let n = 1;

  while (true) {
    const nums = Array.from({ length: BATCH_SIZE }, (_, i) => n + i);
    const results = await Promise.all(nums.map((num) => cognitoGet(token, `/forms/${formId}/entries/${num}`)));

    for (const entry of results) {
      if (entry) entries.push(entry);
    }

    // If every result in the batch was null (404), we've gone past the end.
    if (results.every((r) => r === null)) break;

    n += BATCH_SIZE;
  }

  return entries;
}

// ---------------------------------------------------------------------------
// Shared processing — extract location from a Cognito address object
// ---------------------------------------------------------------------------

const cityMap = new Map();
let skipped = 0;

function processAddress(addr, attendeeCount) {
  if (!addr) {
    skipped += attendeeCount;
    return;
  }

  const country = (addr.CountryCode || addr.Country || 'US').trim();
  const city = (addr.City || '').trim();
  const state = (addr.State || '').trim();
  const zip = (addr.PostalCode || '').trim();

  if (country === 'US' || country === 'United States') {
    // Use State directly from Cognito — already a 2-letter code.
    if (!state && !zip) {
      skipped += attendeeCount;
      return;
    }

    let resolvedState = state;
    let resolvedCity = city;
    let lat = null;
    let lng = null;

    // Optionally enrich with lat/lng from zip lookup.
    if (zip) {
      const info = zipcodes.lookup(zip.substring(0, 5));
      if (info) {
        resolvedState = resolvedState || info.state;
        resolvedCity = resolvedCity || info.city;
        lat = info.latitude;
        lng = info.longitude;
      }
    }

    if (!resolvedState) {
      skipped += attendeeCount;
      return;
    }

    const key = `${resolvedCity || resolvedState}, ${resolvedState}`;
    const existing = cityMap.get(key);
    if (existing) {
      existing.count += attendeeCount;
    } else {
      cityMap.set(key, {
        name: key,
        country: 'US',
        state: resolvedState,
        lat,
        lng,
        count: attendeeCount,
      });
    }
  } else if (country === 'CA' || country === 'Canada') {
    const fsa = zip ? zip.substring(0, 3).toUpperCase() : '';
    const caInfo = fsa ? lookupCanadianFSA(fsa) : null;
    const resolvedCity = city || fsa || 'Canada';
    const resolvedState = caInfo?.province ?? state ?? null;
    const key = `${resolvedCity}, CA`;
    const existing = cityMap.get(key);
    if (existing) {
      existing.count += attendeeCount;
    } else {
      cityMap.set(key, {
        name: key,
        country: 'CA',
        state: resolvedState,
        lat: caInfo?.lat ?? null,
        lng: caInfo?.lng ?? null,
        count: attendeeCount,
      });
    }
  } else {
    if (!city && !country) {
      skipped += attendeeCount;
      return;
    }
    const isoCountry = normalizeCountryCode(country);
    const key = city ? `${city}, ${isoCountry}` : isoCountry;
    const existing = cityMap.get(key);
    if (existing) {
      existing.count += attendeeCount;
    } else {
      cityMap.set(key, { name: key, country: isoCountry, state: null, lat: null, lng: null, count: attendeeCount });
    }
  }
}

function writeOutput() {
  const cities = Array.from(cityMap.values()).sort((a, b) => b.count - a.count);
  const output = { generatedAt: new Date().toISOString(), cities };
  fs.writeFileSync(outputFile, JSON.stringify(output, null, 2));
  console.log(`\n✓ ${cities.length} cities, ${skipped} skipped`);
  console.log(`  Output: ${outputFile}`);
  console.log('\nTop cities:');
  cities.slice(0, 10).forEach((c) => console.log(`  ${c.name}: ${c.count}`));
}

// ---------------------------------------------------------------------------
// API mode
// ---------------------------------------------------------------------------

async function runApiMode() {
  const token = process.env.COGNITO_API_KEY;

  console.log('Fetching forms from Cognito…');
  const allForms = await cognitoGet(token, '/forms');
  if (!Array.isArray(allForms)) throw new Error('Unexpected response from /api/forms');

  // Filter to real event registration forms, excluding drafts/demos/etc.
  const eventForms = allForms.filter((f) => {
    const name = f.Name.toLowerCase();
    const excluded = FORM_NAME_EXCLUDES.some((x) => name.includes(x));
    const included = FORM_NAME_REQUIRES.some((x) => name.includes(x));
    return !excluded && included;
  });

  console.log(`Found ${eventForms.length} event registration forms (${allForms.length} total):`);
  eventForms.forEach((f) => console.log(`  [${f.Id}] ${f.Name}`));

  const seenEmails = new Set();
  let totalEntries = 0;
  let totalAttendees = 0;
  let totalDupes = 0;

  for (const form of eventForms) {
    process.stdout.write(`\n  ${form.Name}: fetching entries…`);
    const entries = await fetchAllEntries(token, form.Id);
    process.stdout.write(` ${entries.length} entries\n`);
    totalEntries += entries.length;

    for (const entry of entries) {
      // Skip incomplete entries.
      if (entry.Entry?.Status === 'Incomplete') continue;

      const primaryEmail = (entry.Email || '').toLowerCase().trim();
      const attendees = Array.isArray(entry.AttendeeInformation) ? entry.AttendeeInformation : [];
      const attendeeCount = Math.max(attendees.length, 1);

      // Deduplicate by primary email across all forms.
      if (primaryEmail) {
        if (seenEmails.has(primaryEmail)) {
          totalDupes++;
          continue;
        }
        seenEmails.add(primaryEmail);
      }

      totalAttendees += attendeeCount;
      processAddress(entry.Address, attendeeCount);
    }
  }

  console.log(
    `\nTotal: ${totalEntries} entries, ${totalAttendees} attendees, ${totalDupes} duplicate registrations removed`
  );
  writeOutput();
}

// ---------------------------------------------------------------------------
// CSV mode — read from local file
// ---------------------------------------------------------------------------

function runCsvMode() {
  const inputFile = process.argv[2] ?? path.join(__dirname, 'input', 'members.csv');

  if (!fs.existsSync(inputFile)) {
    console.log('No COGNITO_API_KEY and no input CSV found — skipping member location processing.');
    console.log('  Set COGNITO_API_KEY to fetch live data, or place a CSV at scripts/input/members.csv.');
    return;
  }

  const raw = fs.readFileSync(inputFile, 'utf-8').trim();
  const lines = raw.split('\n');
  const headers = lines[0].split(',').map((h) => h.trim().replace(/^"|"$/g, '').toLowerCase());

  function getCol(row, ...names) {
    for (const name of names) {
      const idx = headers.indexOf(name.toLowerCase());
      if (idx !== -1) return row[idx]?.trim().replace(/^"|"$/g, '') ?? '';
    }
    return '';
  }

  for (let i = 1; i < lines.length; i++) {
    const line = lines[i].trim();
    if (!line) continue;
    const row = line.split(',').map((v) => v.trim().replace(/^"|"$/g, ''));
    const zip = getCol(row, 'zip', 'zip code', 'zip_code', 'postal code', 'postal_code');
    const country = getCol(row, 'country', 'country code') || 'US';
    const city = getCol(row, 'city');
    const state = getCol(row, 'state');
    processAddress({ CountryCode: country, City: city, State: state, PostalCode: zip }, 1);
  }

  writeOutput();
}

// ---------------------------------------------------------------------------
// Canadian FSA → province + approximate centroid
// ---------------------------------------------------------------------------

const CA_FSA_TABLE = {
  V: { province: 'BC', lat: 49.28, lng: -123.12 },
  T: { province: 'AB', lat: 51.05, lng: -114.07 },
  S: { province: 'SK', lat: 52.13, lng: -106.67 },
  R: { province: 'MB', lat: 49.9, lng: -97.14 },
  K: { province: 'ON', lat: 45.42, lng: -75.69 },
  L: { province: 'ON', lat: 43.7, lng: -79.42 },
  M: { province: 'ON', lat: 43.65, lng: -79.38 },
  N: { province: 'ON', lat: 43.25, lng: -81.5 },
  P: { province: 'ON', lat: 46.5, lng: -80.99 },
  G: { province: 'QC', lat: 46.81, lng: -71.21 },
  H: { province: 'QC', lat: 45.5, lng: -73.57 },
  J: { province: 'QC', lat: 45.43, lng: -73.08 },
  E: { province: 'NB', lat: 46.5, lng: -66.5 },
  B: { province: 'NS', lat: 44.65, lng: -63.58 },
  C: { province: 'PE', lat: 46.24, lng: -63.13 },
  A: { province: 'NL', lat: 47.56, lng: -52.71 },
};

function lookupCanadianFSA(fsa) {
  return CA_FSA_TABLE[fsa.charAt(0).toUpperCase()] ?? null;
}

// ---------------------------------------------------------------------------
// Country code normalization
// ---------------------------------------------------------------------------

const COUNTRY_NAME_MAP = {
  'united states': 'US',
  usa: 'US',
  canada: 'CA',
  'united kingdom': 'GB',
  uk: 'GB',
  england: 'GB',
  germany: 'DE',
  france: 'FR',
  australia: 'AU',
  'new zealand': 'NZ',
  japan: 'JP',
  brazil: 'BR',
  mexico: 'MX',
  ireland: 'IE',
  netherlands: 'NL',
  sweden: 'SE',
  norway: 'NO',
  denmark: 'DK',
  switzerland: 'CH',
};

function normalizeCountryCode(value) {
  if (!value) return value;
  if (value.length === 2) return value.toUpperCase();
  return COUNTRY_NAME_MAP[value.toLowerCase()] ?? value.substring(0, 2).toUpperCase();
}

// ---------------------------------------------------------------------------
// ---------------------------------------------------------------------------
// JSON merge mode — combines files from scripts/input/member-locations/
// ---------------------------------------------------------------------------

// Normalize city names: title-case words, but keep short tokens (state/country codes) uppercase.
function normalizeCity(s) {
  return s
    .trim()
    .split(/,\s*/)
    .map((part, i) => {
      const trimmed = part.trim();
      if (i > 0 && trimmed.length <= 3) return trimmed.toUpperCase();
      return trimmed.replace(/\w+/g, (w) => w.charAt(0).toUpperCase() + w.slice(1).toLowerCase());
    })
    .join(', ');
}

// Geocode a city name via Nominatim (OSM). Returns { lat, lng } or null.
// Nominatim ToS requires max 1 req/sec and a descriptive User-Agent.
async function geocodeCity(cityName) {
  await new Promise((r) => setTimeout(r, 1100)); // respect 1 req/sec limit
  try {
    const url = `https://nominatim.openstreetmap.org/search?q=${encodeURIComponent(cityName)}&format=json&limit=1`;
    const res = await fetch(url, {
      headers: { 'User-Agent': 'ECRSWebsite-build/1.0 (izakizak@gmail.com)' },
    });
    const data = await res.json();
    if (!data.length) return null;
    return { lat: parseFloat(data[0].lat), lng: parseFloat(data[0].lon) };
  } catch {
    return null;
  }
}

async function runJsonMergeMode(jsonFiles) {
  console.log(`Merging ${jsonFiles.length} JSON export(s) from scripts/input/member-locations/:`);
  jsonFiles.forEach((f) => console.log(`  ${path.basename(f)}`));

  const merged = new Map(); // key → MemberCity

  for (const file of jsonFiles) {
    const data = JSON.parse(fs.readFileSync(file, 'utf-8'));
    const cities = Array.isArray(data.cities) ? data.cities : [];
    for (const city of cities) {
      const normalizedName = normalizeCity(city.name);
      const key = `${normalizedName}|${city.country}`;
      const existing = merged.get(key);
      if (existing) {
        existing.count += city.count;
        // Upgrade lat/lng if we now have it and didn't before
        if (existing.lat === null && city.lat !== null) {
          existing.lat = city.lat;
          existing.lng = city.lng;
        }
      } else {
        merged.set(key, { ...city, name: normalizedName });
      }
    }
  }

  // Geocode any cities still missing lat/lng via Nominatim
  const needsGeocode = Array.from(merged.values()).filter((c) => c.lat === null);
  if (needsGeocode.length > 0) {
    console.log(`\nGeocoding ${needsGeocode.length} cities via Nominatim…`);
    for (const city of needsGeocode) {
      process.stdout.write(`  ${city.name}… `);
      const coords = await geocodeCity(city.name);
      if (coords) {
        city.lat = coords.lat;
        city.lng = coords.lng;
        process.stdout.write(`${coords.lat.toFixed(3)}, ${coords.lng.toFixed(3)}\n`);
      } else {
        process.stdout.write('not found\n');
      }
    }
  }

  const cities = Array.from(merged.values()).sort((a, b) => b.count - a.count);
  const output = { generatedAt: new Date().toISOString(), cities };
  fs.writeFileSync(outputFile, JSON.stringify(output, null, 2));

  const total = cities.reduce((s, c) => s + c.count, 0);
  const geocoded = cities.filter((c) => c.lat !== null).length;
  console.log(`\n✓ ${cities.length} cities (${geocoded} geocoded), ${total} total attendees`);
  console.log(`  Output: ${outputFile}`);
  console.log('\nTop cities:');
  cities.slice(0, 10).forEach((c) => console.log(`  ${c.name}: ${c.count}`));
}

// ---------------------------------------------------------------------------
// Entry point
// ---------------------------------------------------------------------------

const jsonFiles = fs.existsSync(jsonInputDir)
  ? fs
      .readdirSync(jsonInputDir)
      .filter((f) => f.endsWith('.json'))
      .map((f) => path.join(jsonInputDir, f))
  : [];

if (jsonFiles.length > 0) {
  runJsonMergeMode(jsonFiles).catch((err) => {
    console.error(err);
    process.exit(1);
  });
} else if (process.env.COGNITO_API_KEY) {
  runApiMode().catch((err) => {
    console.error(err);
    process.exit(1);
  });
} else {
  runCsvMode();
}
